from enum import Enum from dataclasses import dataclass from datetime import datetime import structlog
logger = structlog.get_logger()
class EventType(Enum): USER_REGISTERED = "user.registered" ORDER_CREATED = "order.created" PAYMENT_COMPLETED = "payment.completed" PAYMENT_FAILED = "payment.failed"
@dataclass class BusinessEvent: event_type: EventType entity_type: str entity_id: str data: dict timestamp: datetime = None
def __post_init__(self): if self.timestamp is None: self.timestamp = datetime.utcnow()
def log_business_event(event: BusinessEvent): """Log a business event for audit and analytics.""" logger.info( event.event_type.value, entity_type=event.entity_type, entity_id=event.entity_id, timestamp=event.timestamp.isoformat(), **event.data )
# Usage log_business_event(BusinessEvent( event_type=EventType.PAYMENT_COMPLETED, entity_type="order", entity_id=order.id, data={ "customer_id": order.customer_id, "total": float(order.total), "items_count": len(order.items), "payment_method": order.payment_method, } ))

import re
from typing import Any
import structlog

SENSITIVE_PATTERNS = [
    (r'\b\d{16}\b', '****-****-****-****'),  # Credit card
    (r'\b\d{3}-\d{2}-\d{4}\b', '***-**-****'),  # SSN
    (r'password["\s:=]+["\']?([^"\'\s]+)', 'password: [REDACTED]'),
    (r'api[_-]?key["\s:=]+["\']?([^"\'\s]+)', 'api_key: [REDACTED]'),
]

SENSITIVE_FIELDS = {'password', 'secret', 'token', 'api_key', 'ssn', 'credit_card'}

def mask_sensitive_dict(data: dict) -> dict:
    """Recursively mask sensitive fields in dictionaries."""
    masked = {}
    for key, value in data.items():
        if key.lower() in SENSITIVE_FIELDS:
            masked[key] = "[REDACTED]"
        elif isinstance(value, dict):
            masked[key] = mask_sensitive_dict(value)
        elif isinstance(value, str):
            masked[key] = re.sub(
                '|'.join(p[0] for p in SENSITIVE_PATTERNS),
                lambda m: next(r for p, r in SENSITIVE_PATTERNS if re.search(p, m.group())),
                value,
                flags=re.IGNORECASE
            )
        else:
            masked[key] = value
    return masked

def sensitive_data_processor(logger, method_name, event_dict):
    """structlog processor to mask sensitive data."""
    return mask_sensitive_dict(event_dict)

structlog.configure(
    processors=[
        structlog.contextvars.merge_contextvars,
        sensitive_data_processor,
        structlog.processors.JSONRenderer()
    ]
)

import time
from contextlib import contextmanager
from functools import wraps
import structlog

logger = structlog.get_logger()

@contextmanager
def log_timing(operation: str, **context):
    """Context manager to log operation timing."""
    start = time.perf_counter()
    try:
        yield
    finally:
        duration_ms = (time.perf_counter() - start) * 1000
        logger.info(
            f"{operation} completed",
            duration_ms=round(duration_ms, 2),
            **context
        )

def log_slow_operations(threshold_ms: float = 100):
    """Decorator to log slow operations."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            start = time.perf_counter()
            result = func(*args, **kwargs)
            duration_ms = (time.perf_counter() - start) * 1000

            if duration_ms > threshold_ms:
                logger.warning(
                    "Slow operation detected",
                    function=func.__name__,
                    duration_ms=round(duration_ms, 2),
                    threshold_ms=threshold_ms
                )

            return result
        return wrapper
    return decorator

# Usage
@log_slow_operations(threshold_ms=50)
def process_data(data: list) -> list:
    return [transform(item) for item in data]

with log_timing("database_query", table="users", query_type="select"):
